const session = ($json.session && typeof $json.session === 'object') ? $json.session : {};

// Postgres node in n8n usually returns rows in $json or in items array.
// Here we assume this Function receives merged input where PG output is in $json (one row).
// If PG output is in $json[0] style, adjust by inspecting actual output once.

const request_tz = $json.request_tz ?? null;
const user_tz = $json.user_tz ?? null;

const tz =
  session?.initiator_timezone ??
  request_tz ??
  user_tz ??
  null;

const need_tz = (tz === null || String(tz).trim() === "");

return [{
  json: {
    ...$json,
    tz: need_tz ? null : String(tz),
    need_tz
  }
}];

// FN_SET_SESSION_TZ_PENDING_199 (железобетонно сохраняет active_request_id)

let session = $json.session;
if (!session || typeof session !== "object") session = {};

// active_request_id: пытаемся восстановить из самых стабильных мест
const active_request_id =
  session.active_request_id ??
  $json.active_request_id ??
  $node["PAY__FN_PARSE_SESSION"]?.json?.session?.active_request_id ?? // если ты в PAY-цепочке
  $node["PAY__FN_PARSE_SESSION"]?.json?.active_request_id ??
  null;

if (!active_request_id) {
  return [{
    json: {
      ...$json,
      fatal: true,
      fatal_reason: "NO_ACTIVE_REQUEST_ID_WHEN_SET_TZ_PENDING",
      session
    }
  }];
}

// 1) НЕ ТЕРЯЕМ active_request_id
session.active_request_id = String(active_request_id);

// 2) Ставим ожидание TZ + pending тариф
session.awaiting = "tz";
session.tariff_pending = 199; // числом

// 3) Дефолты структуры
session.current_variant_idx = session.current_variant_idx ?? "0";
session.last_variant_idx = session.last_variant_idx ?? "0";
session.recipient_name = session.recipient_name ?? null;
session.initiator_timezone = session.initiator_timezone ?? null;

return [{ json: { ...$json, session, fatal: false } }];

